arguments.command:
# Get nearest named symbol for the SGen worker addresses
aarch64-linux-gnu-nm -C /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk -v a1=0x2f4b20 -v a2=0x2f4c84 '
  /^[0-9a-f]+ [tTwW]/ {
    addr = strtonum("0x" $1)
    name = $3
    if (addr <= strtonum(a1)) { sym1_addr = $1; sym1_name = name }
    if (addr <= strtonum(a2)) { sym2_addr = $1; sym2_name = name }
  }
  END {
    print "0x2f4b20 -> " sym1_name " (at 0x" sym1_addr ")"
    print "0x2f4c84 -> " sym2_name " (at 0x" sym2_addr ")"
  }
'

